```hcl
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
  }
}
```

3) GitHub Actions gate:
```yaml
- name: Init and Plan
  run: |
    terraform init -backend-config=env/${{ env }}/backend.hcl
    terraform plan -out=tfplan -var-file=env/${{ env }}/terraform.tfvars
    terraform show -json tfplan > plan.json
