Implementation involves three components:

**1. CIDR Validation Function (module-level)**
```hcl
locals {
  cidr_overlap_check = [for cidr in var.subnet_cidrs : {
    cidr   = cidr
    result = length([for existing in var.existing_cidrs : 1 if cidrnetmask(cidr) <= cidrnetmask(existing) && cidrcontains(existing, cidr)])
  }]

  has_overlaps = sum([for item in local.cidr_overlap_check : item.result]) > 0
}

resource "null_resource" "cidr_validation" {
  count = local.has_overlaps ? 1 : 0
  triggers = {
    overlap_detected = jsonencode(local.cidr_overlap_check)
  }

  provisioner "local-exec" {
    command = "echo 'ERROR: CIDR overlap detected: ${join(", ", [for item in local.cidr_overlap_check : item.cidr if item.result > 0])}' && exit 1"
  }
}
```

**2. External Data Script**
```python
#!/usr/bin/env python3
import json
import boto3

def fetch_allocated_cidrs(region):
    client = boto3.client('ec2', region_name=region)
    response = client.describe_vpcs()
    cidrs = [vpc.get('CidrBlock') for vpc in response.get('Vpcs', [])]
    return cidrs

if __name__ == "__main__":
    regions = ["us-east-1", "us-west-2", "eastus"]
    registry = {region: fetch_allocated_cidrs(region) for region in regions}
    print(json.dumps(registry))
```

**3. Workflow & Plan-Check Gate**
```yaml
cidr-guard:
  script:
    - python3 scripts/fetch_cidr_registry.py > cidr_registry.json
    - terraform plan -var-file=cidr_registry.json -out=tfplan
    - terraform show -json tfplan | jq -r '.resource_changes[] | select(.type=="null_resource" and .change.actions[]=="create")'
  rules:
    - if: '$CI_COMMIT_BRANCH == "main"'
      allow_failure: false
```

