variable "tenants" {
  type = map(object({ cloud = string, region = string }))
}

provider "aws" {
  alias  = "tenant_${each.key}"
  region = var.tenants[each.key].region
  # fetch creds from Vault here
}

provider "azurerm" {
  alias   = "tenant_${each.key}"
  features = {}
