Implement a Python gate script that loads `plan.json` (generated via `terraform show -json plan.out`), iterates through `resource_changes` for security group updates, and exits with a non-zero code if any prod-tagged security group gains ingress rules from `0.0.0.0/0`.

**1. Python gate script:**

```python
import json
import sys

def check_plan(plan_json):
    with open(plan_json, 'r') as f:
        plan = json.load(f)

    violations = []

    for change in plan.get('resource_changes', []):
        resource_type = change.get('type', '')
        if resource_type not in ('aws_security_group', 'aws_security_group_rule'):
            continue

        change_actions = change.get('change', {}).get('actions', [])
        if 'create' not in change_actions and 'update' not in change_actions:
            continue

        tags = change.get('change', {}).get('after', {}).get('tags', {})
        if tags.get('environment') != 'prod':
            continue

        after_values = change.get('change', {}).get('after', {})

        if resource_type == 'aws_security_group':
            for rule in after_values.get('ingress', []):
                if '0.0.0.0/0' in rule.get('cidr_blocks', []):
                    violations.append(f"{change['address']} adds 0.0.0.0/0 ingress")

        if resource_type == 'aws_security_group_rule':
            if '0.0.0.0/0' in after_values.get('cidr_blocks', []) and after_values.get('type', '') == 'ingress':
                violations.append(f"{change['address']} adds 0.0.0.0/0 ingress")

    return violations

if __name__ == '__main__':
    violations = check_plan(sys.argv[1] if len(sys.argv) > 1 else 'plan.json')
    if violations:
        print('VIOLATIONS FOUND:')
        for v in violations:
            print(f'  - {v}')
        sys.exit(1)
```

**2. GitHub Actions step:**

```yaml
- name: Run Terraform Plan
  run: terraform plan -out=plan.out

- name: Convert Plan to JSON
  run: terraform show -json plan.out > plan.json

- name: Security Group Gate
  run: python3 scripts/tf_security_gate.py plan.json
```

**3. Example plan.json snippet showing prohibited change:**

```json
{
  "resource_changes": [
    {
      "address": "aws_security_group.prod_web",
      "type": "aws_security_group",
      "change": {
        "actions": ["update"],
        "after": {
          "tags": {
            "environment": "prod"
          },
          "ingress": [
            {
              "cidr_blocks": ["0.0.0.0/0"],
              "from_port": 443,
              "to_port": 443,
              "protocol": "tcp"
            }
          ]
        }
      }
    }
