```yaml
name: Terraform Validation
on: [pull_request]
jobs:
  validate:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: hashicorp/setup-terraform@v3
        with:
          terraform_version: 1.6

      - name: Init terraform
        run: terraform init -backend-config="key=state/${{ matrix.environment }}/logs.tfstate"
        env:
          AWS_ACCESS_KEY_ID: ${{ secrets.AWS_ACCESS_KEY_ID }}
          AWS_SECRET_ACCESS_KEY: ${{ secrets.AWS_SECRET_ACCESS_KEY }}
        matrix:
          environment: [dev, stage, prod]

      - name: Validate bucket naming
        run: |
          BUCKET_NAME=$(terraform output -raw bucket_name)
          if [[ "$BUCKET_NAME" != *"${{ matrix.environment }}"* ]]; then
            echo "Error: Bucket name must contain environment: $BUCKET_NAME"
            exit 1
          fi

      - name: Validate encryption enabled
        run: |
          ENCRYPTION=$(terraform output -raw encryption_enabled)
          if [ "$ENCRYPTION" != "true" ]; then
            echo "Error: S3 bucket encryption must be enabled"
            exit 1
          fi
